import { Button } from "@/components/ui/button";
import { Card, CardAction, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Command as UICommand,
  CommandGroup,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import { Tool } from "@/registry/commandly/lib/types/commandly";
import { exportToStructuredJSON } from "@/registry/commandly/lib/utils/commandly";
import { convertToNestedStructure } from "@/registry/commandly/lib/utils/commandly-nested";
import { CheckIcon, ChevronsUpDownIcon, CopyIcon } from "lucide-react";
import { useQueryState } from "nuqs";
import { useEffect, useState } from "react";
import { toast } from "sonner";

const jsonOptions = [
  { value: "nested", label: "Nested" },
  { value: "flat", label: "Flat" },
];

interface JsonTypeComponentProps {
  tool: Tool;
}

export function JsonOutput({ tool }: JsonTypeComponentProps) {
  const [open, setOpen] = useState(false);
  const [jsonString, setJsonString] = useState<string>();
  const [jsonType, setJsonType] = useQueryState("output", {
    defaultValue: "flat",
  });
  useEffect(() => {
    const config =
      jsonType === "flat" ? exportToStructuredJSON(tool) : convertToNestedStructure(tool);
    setJsonString(JSON.stringify(config, null, 2));
  }, [jsonType, tool]);

  return (
    <Card>
      <CardHeader>
        <CardTitle>
          <span className="text-sm">Output type: </span>
          <Popover
            open={open}
            onOpenChange={setOpen}
          >
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                role="combobox"
                aria-expanded={open}
                className="w-48 justify-between"
              >
                {jsonOptions.find((option) => option.value === jsonType)?.label}
                <ChevronsUpDownIcon className="opacity-50" />
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-48 p-0">
              <UICommand>
                <CommandList>
                  <CommandGroup>
                    {jsonOptions.map((option) => (
                      <CommandItem
                        key={option.value}
                        value={option.value}
                        onSelect={(currentValue) => {
                          setJsonType(currentValue);
                          setOpen(false);
                        }}
                      >
                        {option.label}
                        <CheckIcon
                          className={cn(
                            "ml-auto h-4 w-4",
                            jsonType === option.value ? "opacity-100" : "opacity-0",
                          )}
                        />
                      </CommandItem>
                    ))}
                  </CommandGroup>
                </CommandList>
              </UICommand>
            </PopoverContent>
          </Popover>
        </CardTitle>
        <CardAction
          className="rounded-md"
          onClick={() => {
            navigator.clipboard.writeText(jsonString!);
            toast("Copied!");
          }}
        >
          <CopyIcon className="h-4 w-4 dark:stroke-primary" />
        </CardAction>
      </CardHeader>
      <CardContent>
        <ScrollArea
          className="max-w-full *:data-radix-scroll-area-viewport:max-h-[calc(100vh-320px)]"
          type="hover"
        >
          <pre className="max-h max-w-full rounded-md bg-card font-mono text-sm dark:text-gray-200">
            {jsonString}
          </pre>
          <ScrollBar orientation="vertical" />
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      </CardContent>
    </Card>
  );
}

export interface Command {
  key: string;
  parentCommandKey?: string;
  name: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface ParameterEnumValue {
  key: string;
  parameterKey: string;
  value: string;
  displayName: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export type ParameterValidationType = "min_length" | "max_length" | "min_value" | "max_value" | "regex";

export interface ParameterValidation {
  key: string;
  parameterKey: string;
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export type ParameterDependencyType = "requires" | "conflicts_with";

export interface ParameterDependency {
  key: string;
  parameterKey: string;
  dependsOnParameterKey: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export type ParameterValue = string | number | boolean;

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface Register {}

export type ParameterMetadata = Register extends { parameterMetadata: infer M } ? M : { tags?: string[] };

export type ParameterType = "Flag" | "Option" | "Argument";

export type ParameterDataType = "String" | "Number" | "Boolean" | "Enum";

export interface Parameter {
  key: string;
  name: string;
  commandKey?: string;
  description?: string;
  metadata?: ParameterMetadata;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  isRequired: boolean;
  isRepeatable: boolean;
  isGlobal: boolean;
  defaultValue?: string;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enumValues?: ParameterEnumValue[];
  validations?: ParameterValidation[];
  dependencies?: ParameterDependency[];
}

export type ExclusionType = "mutual_exclusive" | "required_one_of";

export interface ExclusionGroup {
  key?: string;
  commandKey?: string;
  name: string;
  exclusionType: ExclusionType;
  parameterKeys: string[];
}

export interface SavedCommand {
  key: string;
  command: string;
}

export type ToolMetadata = Register extends { toolMetadata: infer M } ? M : Record<string, unknown>;

export interface Tool {
  name: string;
  displayName: string;
  description?: string;
  version?: string;
  category?: string;
  tags?: string[];
  url?: string;
  commands: Command[];
  parameters: Parameter[];
  exclusionGroups?: ExclusionGroup[];
  metadata?: ToolMetadata;
}

import type {
  ExclusionType,
  ParameterDataType,
  ParameterDependencyType,
  ParameterMetadata,
  ParameterType,
  ParameterValidationType,
} from "./commandly";

export interface NestedParameterEnumValue {
  value: string;
  displayName: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface NestedParameterValidation {
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export interface NestedParameterDependency {
  dependsOnParameter: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export interface NestedParameter {
  name: string;
  description?: string;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  metadata?: ParameterMetadata;
  isRequired: boolean;
  isRepeatable: boolean;
  isGlobal: boolean;
  defaultValue?: string;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enumValues?: NestedParameterEnumValue[];
  validations?: NestedParameterValidation[];
  dependencies?: NestedParameterDependency[];
}

export interface NestedCommand {
  name: string;
  description?: string;
  isDefault: boolean;
  sortOrder: number;
  parameters: NestedParameter[];
  subcommands: NestedCommand[];
}

export interface NestedExclusionGroup {
  name: string;
  exclusionType: ExclusionType;
  parameters: string[];
}

export type NestedToolMetadata = Record<string, unknown>;

export interface NestedTool {
  name: string;
  displayName: string;
  description?: string;
  version?: string;
  url?: string;
  globalParameters: NestedParameter[];
  commands: NestedCommand[];
  exclusionGroups?: NestedExclusionGroup[] | null;
  metadata?: NestedToolMetadata;
}
